mapper.select:
SELECT hp.HOMPI_ID, hp.HOMPI_URL, hp.HOMPI_TITLE, hp.OWNER_USER_ID, IFNULL(hds.TODAY_CNT, 0) AS TODAY_CNT, hp.TOTAL_CNT, hc.HOMPI_CONFIG_CODE, hc.HOMPI_CONFIG_CONTENT, ub.NAME, ub.EMAIL, ub.GENDER_CODE, MAX(CASE WHEN hc.HOMPI_CONFIG_CODE = '01' THEN hc.HOMPI_CONFIG_CONTENT END) AS PROFILE_IMAGE, MAX(CASE WHEN hc.HOMPI_CONFIG_CODE = '02' THEN hc.HOMPI_CONFIG_CONTENT END) AS INTRODUCTION, MAX(CASE WHEN hc.HOMPI_CONFIG_CODE = '03' THEN hc.HOMPI_CONFIG_CONTENT END) AS FRIENDS_COMMENT_YN, MAX(CASE WHEN hc.HOMPI_CONFIG_CODE = '04' THEN hc.HOMPI_CONFIG_CONTENT END) AS MOOD, MAX(CASE WHEN hc.HOMPI_CONFIG_CODE = '05' THEN hc.HOMPI_CONFIG_CONTENT END) AS HOMPI_LANG FROM HOMPI hp LEFT OUTER JOIN HOMPI_DAILY_STATS hds ON hp.HOMPI_ID = hds.HOMPI_ID AND hds.DAY_STATS_DATE = '20250323' LEFT OUTER JOIN HOMPI_CONFIG hc ON hp.HOMPI_ID = hc.HOMPI_ID LEFT OUTER JOIN USER_BASIC ub ON hp.OWNER_USER_ID = ub.USER_ID
hp.HOMPI_ID = #{hompiId} AND hp.OWNER_USER_ID = #{ownerUserId}
hp.HOMPI_ID = #{hompiId}

