SELECT OWNER_USER_ID
FROM HOMPI
WHERE HOMPI_ID = #{hompiId}

SELECT COUNT(*)
FROM HOMPI_DAILY_STATS
WHERE DAY_STATS_DATE = #{today}
  AND HOMPI_ID = #{hompiId}

