UPDATE HOMPI_DAILY_STATS hds
    JOIN HOMPI hp
ON hds.HOMPI_ID = hp.HOMPI_ID
    SET hds.TODAY_CNT = hds.TODAY_CNT+1, hp.TOTAL_CNT = hp.TOTAL_CNT+1
WHERE hds.HOMPI_ID = #{hompiId}
  AND hds.DAY_STATS_DATE = #{today}

UPDATE HOMPI
SET TOTAL_CNT = TOTAL_CNT + 1
WHERE HOMPI_ID = #{hompiId}

UPDATE HOMPI_CONFIG


        HOMPI_CONFIG_CONTENT = #{introduction}
        WHERE HOMPI_CONFIG_CODE = '02'


        HOMPI_CONFIG_CONTENT = #{filePath}
        WHERE HOMPI_CONFIG_CODE = '02'


AND WHERE HOMPI_ID = #{hompiId}
